-- ----------------------------
-- Table structure for activity
-- ----------------------------
DROP TABLE IF EXISTS `activity`;
CREATE TABLE `activity`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '活动ID',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '活动标题',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '活动内容',
  `organizer_id` bigint NULL DEFAULT NULL COMMENT '组织者ID',
  `location` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '活动地点',
  `max_participants` int NULL DEFAULT NULL COMMENT '最大参与人数',
  `current_participants` int NULL DEFAULT 0 COMMENT '当前参与人数',
  `start_time` datetime NULL DEFAULT NULL COMMENT '开始时间',
  `end_time` datetime NULL DEFAULT NULL COMMENT '结束时间',
  `status` int NULL DEFAULT 1 COMMENT '状态(0:未开始,1:进行中,2:已结束,3:已取消)',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_organizer_id`(`organizer_id` ASC) USING BTREE,
  INDEX `idx_start_time`(`start_time` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 21 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '活动表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of activity
-- ----------------------------
INSERT INTO `activity` VALUES (1, '健康讲座：高血压预防与护理', '本次讲座将邀请专业医生为大家讲解高血压的预防措施和日常护理方法，帮助老年朋友更好地管理健康。', 2, '社区中心多功能厅', 50, 1, '2026-03-01 09:00:00', '2026-03-01 11:00:00', 2, '2026-02-20 10:00:00', '2026-03-22 14:00:38');
INSERT INTO `activity` VALUES (2, '春季太极晨练活动', '每天早上8点在社区广场进行太极晨练，由专业教练指导，欢迎各位老年朋友参加。', 3, '社区中心广场', 30, 1, '2026-03-15 08:00:00', '2026-03-15 09:00:00', 2, '2026-03-01 10:00:00', '2026-03-22 14:00:38');
INSERT INTO `activity` VALUES (3, '书法兴趣班', '学习中国传统书法艺术，培养兴趣爱好，丰富精神文化生活。', 2, '社区中心书法室', 20, 1, '2026-03-20 14:00:00', '2026-03-20 16:00:00', 2, '2026-03-05 10:00:00', '2026-03-22 14:00:38');
INSERT INTO `activity` VALUES (4, '智能手机使用培训', '教老年朋友如何使用智能手机，包括微信、视频通话、健康码等实用功能。', 3, '社区中心电脑室', 25, 10, '2026-03-25 09:30:00', '2026-03-25 11:30:00', 0, '2026-03-10 10:00:00', '2026-03-22 14:48:26');
INSERT INTO `activity` VALUES (5, '春季踏青活动', '组织老年朋友前往公园踏青赏花，享受春日美好时光。', 2, '市郊公园', 40, 0, '2026-04-01 08:00:00', '2026-04-01 17:00:00', 0, '2026-03-15 10:00:00', '2026-03-22 14:22:12');
INSERT INTO `activity` VALUES (6, '营养膳食讲座', '邀请营养师讲解老年人的营养搭配和膳食建议，帮助大家建立健康的饮食习惯。', 3, '社区中心多功能厅', 50, 0, '2026-04-05 14:00:00', '2026-04-05 16:00:00', 0, '2026-03-20 10:00:00', '2026-03-22 14:22:12');
INSERT INTO `activity` VALUES (7, '手工制作活动', '学习制作简单的手工艺品，锻炼动手能力，体验创作的乐趣。', 2, '社区中心手工室', 20, 0, '2026-04-10 10:00:00', '2026-04-10 12:00:00', 0, '2026-03-25 10:00:00', '2026-03-22 14:22:12');
INSERT INTO `activity` VALUES (8, '棋牌比赛', '举办象棋、围棋等棋牌比赛，增进友谊，锻炼脑力。', 3, '社区中心棋牌室', 30, 0, '2026-04-15 09:00:00', '2026-04-15 17:00:00', 0, '2026-04-01 10:00:00', '2026-03-22 14:22:12');
INSERT INTO `activity` VALUES (9, '广场舞培训', '学习广场舞基本动作和完整舞蹈，锻炼身体，愉悦心情。', 2, '社区中心广场', 40, 0, '2026-04-20 08:00:00', '2026-04-20 10:00:00', 0, '2026-04-05 10:00:00', '2026-03-22 14:22:12');
INSERT INTO `activity` VALUES (10, '健康体检活动', '联合医院为老年朋友提供免费健康体检服务，包括血压、血糖、心电图等检查。', 3, '社区中心医疗室', 60, 0, '2026-04-25 08:00:00', '2026-04-25 17:00:00', 0, '2026-04-10 10:00:00', '2026-03-22 14:22:12');
INSERT INTO `activity` VALUES (11, '歌唱比赛', '举办老年歌唱比赛，展示才艺，丰富文化生活。', 2, '社区中心多功能厅', 50, 0, '2026-05-01 14:00:00', '2026-05-01 17:00:00', 0, '2026-04-15 10:00:00', '2026-03-22 14:00:23');
INSERT INTO `activity` VALUES (12, '端午节包粽子活动', '端午节包粽子活动，传承传统文化，增进邻里感情。', 3, '社区中心食堂', 40, 0, '2026-05-10 09:00:00', '2026-05-10 12:00:00', 0, '2026-04-20 10:00:00', '2026-03-22 14:00:23');
INSERT INTO `activity` VALUES (13, '心理健康讲座', '邀请心理专家讲解老年人心理健康知识，帮助大家保持积极乐观的心态。', 2, '社区中心多功能厅', 50, 0, '2026-05-15 14:00:00', '2026-05-15 16:00:00', 0, '2026-04-25 10:00:00', '2026-03-22 14:00:23');
INSERT INTO `activity` VALUES (14, '摄影兴趣班', '学习摄影技巧，记录生活中的美好瞬间。', 3, '社区中心摄影室', 20, 0, '2026-05-20 09:00:00', '2026-05-20 11:00:00', 0, '2026-05-01 10:00:00', '2026-03-22 14:00:23');
INSERT INTO `activity` VALUES (15, '夏季养生讲座', '讲解夏季养生知识，包括饮食、运动、作息等方面的建议。', 2, '社区中心多功能厅', 50, 0, '2026-05-25 14:00:00', '2026-05-25 16:00:00', 0, '2026-05-05 10:00:00', '2026-03-22 14:00:23');
