INSERT INTO `activity` VALUES (17, '园艺种植活动', '学习花卉种植技巧，美化家居环境，陶冶情操。', 2, '社区中心花园', 30, 0, '2026-06-05 09:00:00', '2026-06-05 11:00:00', 0, '2026-05-15 10:00:00', '2026-03-22 14:00:23');
