-- ----------------------------
-- Table structure for health_record
-- ----------------------------
DROP TABLE IF EXISTS `health_record`;
CREATE TABLE `health_record`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `record_time` date NULL DEFAULT NULL COMMENT '记录时间',
  `blood_pressure` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '血压',
  `temperature` decimal(4, 2) NULL DEFAULT NULL COMMENT '体温',
  `blood_sugar` decimal(5, 2) NULL DEFAULT NULL COMMENT '血糖',
  `heart_rate` int NULL DEFAULT NULL COMMENT '心率',
  `weight` decimal(5, 2) NULL DEFAULT NULL COMMENT '体重',
  `height` decimal(5, 2) NULL DEFAULT NULL COMMENT '身高',
  `health_status` int NULL DEFAULT NULL COMMENT '健康状态(0:异常,1:正常)',
  `white_blood_cell` decimal(6, 2) NULL DEFAULT NULL COMMENT '白细胞计数',
  `hemoglobin` decimal(6, 2) NULL DEFAULT NULL COMMENT '血红蛋白',
  `hematocrit` decimal(6, 2) NULL DEFAULT NULL COMMENT '红细胞压积',
  `platelet_count` decimal(8, 2) NULL DEFAULT NULL COMMENT '血小板计数',
  `alt` decimal(6, 2) NULL DEFAULT NULL COMMENT '谷丙转氨酶',
  `ast` decimal(6, 2) NULL DEFAULT NULL COMMENT '谷草转氨酶',
  `ggt` decimal(6, 2) NULL DEFAULT NULL COMMENT '谷氨酰转肽酶',
  `alp` decimal(6, 2) NULL DEFAULT NULL COMMENT '碱性磷酸酶',
  `total_protein` decimal(6, 2) NULL DEFAULT NULL COMMENT '总蛋白',
  `albumin` decimal(6, 2) NULL DEFAULT NULL COMMENT '白蛋白',
  `creatinine` decimal(6, 2) NULL DEFAULT NULL COMMENT '肌酐',
  `blood_urea_nitrogen` decimal(6, 2) NULL DEFAULT NULL COMMENT '血尿素氮',
  `egfr` decimal(8, 2) NULL DEFAULT NULL COMMENT '肾小球滤过率',
  `uric_acid` decimal(6, 2) NULL DEFAULT NULL COMMENT '尿酸',
  `total_cholesterol` decimal(6, 2) NULL DEFAULT NULL COMMENT '总胆固醇',
  `triglycerides` decimal(6, 2) NULL DEFAULT NULL COMMENT '甘油三酯',
  `ldl_cholesterol` decimal(6, 2) NULL DEFAULT NULL COMMENT '低密度脂蛋白胆固醇',
  `hdl_cholesterol` decimal(6, 2) NULL DEFAULT NULL COMMENT '高密度脂蛋白胆固醇',
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '备注',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_record_time`(`record_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 11 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '健康档案表' ROW_FORMAT = DYNAMIC;

