INSERT INTO `news` VALUES (1, '社区中心开放通知', '社区中心将于2026年4月1日正式对外开放，欢迎各位居民前来参观体验。我们将提供健康服务、文体活动、生活服务等多种服务。', 1, 1, '2026-03-22 10:00:00', 1, 150, '2026-03-22 10:00:00', '2026-03-22 10:00:00');
INSERT INTO `news` VALUES (2, '健康讲座通知', '本周六上午10点将在多功能活动室举办健康讲座，主题为\"老年人养生保健\"，欢迎各位老年朋友参加。', 1, 2, '2026-03-22 14:00:00', 1, 89, '2026-03-22 14:00:00', '2026-03-22 14:00:00');
INSERT INTO `news` VALUES (3, '社区举办春季运动会', '为丰富社区居民的文化生活，增进邻里感情，社区中心将于4月中旬举办春季运动会，设有多项趣味运动项目。', 1, 1, '2026-03-20 09:00:00', 1, 230, '2026-03-20 09:00:00', '2026-03-22 17:31:54');
INSERT INTO `news` VALUES (4, '养老服务政策解读', '最新发布的养老服务政策为老年人提供了更多福利，包括医疗补贴、居家养老服务等内容。本文将详细解读政策要点。', 1, 1, '2026-03-18 16:00:00', 1, 312, '2026-03-18 16:00:00', '2026-03-22 17:31:54');
INSERT INTO `news` VALUES (5, '社区志愿者招募', '社区中心现面向全体居民招募志愿者，参与社区服务活动，为社区建设贡献力量。有意者请联系社区中心。', 1, 2, '2026-03-15 11:00:00', 1, 179, '2026-03-15 11:00:00', '2026-03-22 17:31:54');
INSERT INTO `news` VALUES (6, '健康体检活动通知', '社区中心将于4月5日组织免费健康体检活动，为65岁以上老年人提供全面体检服务，请提前预约。', 1, 1, '2026-03-25 09:00:00', 1, 121, '2026-03-25 09:00:00', '2026-03-25 09:00:00');
INSERT INTO `news` VALUES (7, '书法培训班开班', '社区中心书法培训班将于4月10日正式开班，由专业书法老师授课，欢迎书法爱好者报名参加。', 1, 2, '2026-03-23 14:00:00', 1, 96, '2026-03-23 14:00:00', '2026-03-22 17:31:54');
INSERT INTO `news` VALUES (8, '老年人防诈骗知识讲座', '为提高老年人的防诈骗意识，社区中心将于4月15日举办防诈骗知识讲座，讲解常见诈骗手段和防范方法。', 1, 1, '2026-03-24 10:00:00', 1, 146, '2026-03-24 10:00:00', '2026-03-24 10:00:00');
INSERT INTO `news` VALUES (9, '社区食堂开业通知', '社区中心食堂将于4月1日正式开业，提供营养配餐服务，欢迎各位居民前来用餐。', 1, 2, '2026-03-26 11:00:00', 1, 202, '2026-03-26 11:00:00', '2026-03-26 11:00:00');
INSERT INTO `news` VALUES (10, '春季养生指南', '春季是养生的好时节，本文为大家介绍春季养生的注意事项和健康饮食建议。', 1, 1, '2026-03-19 15:00:00', 1, 267, '2026-03-19 15:00:00', '2026-03-22 17:31:54');
INSERT INTO `news` VALUES (11, '江苏科技创新和产业创新深度融合气象新（“十五五”开好局起好步）', '要夹住一根直径约0.06毫米的头发，可以用镊子。\n\n　　如何“夹住”直径仅有头发1/3000的颗粒物？\n\n　　江苏苏州高新区一间校企联合省重点实验室内，从半导体激光器上射出的一束光，在微米级的传感器芯片上形成一把“光镊”，“夹住”了颗粒物。根据大屏幕上实时显示的光谱影像，科研人员有条不紊地进行检测分析实验。\n\n　　这把灵敏的“光镊”，由南京大学集成电路学院寇君龙副教授团队与苏州长光华芯光电技术股份有限公司协力研发。\n\n　　今年全国两会期间，习近平总书记在参加江苏代表团审议时强调：“在促进创新链产业链资金链人才链深度融合、推动科技成果高效转化应用上探索新途径”。2025年全国两会期间，习近平总书记在参加江苏代表团审议时指出：“抓科技创新，要着眼建设现代化产业体系，坚持教育、科技、人才一起抓”。“十五五”规划纲要提出，“推动科技创新和产业创新深度融合”。\n\n　　深入贯彻落实习近平总书记重要指示精神和党中央决策部署，江苏18个高新区和37家高校协同发展、双向赋能，探索“有组织科研+有组织转化”的“双高协同”模式，推动科技创新和产业创新深度融合。\n\n　　依托优势产业建设学科专业——\n\n　　目前，南京大学建在苏州高新区的新校区已全面投用。“我们围绕苏州产业实际，陆续建设了集成电路、机器人与自动化等十大学院。”南京大学校长助理姜田举例说，集成电路学院与龙头企业长光华芯共建重点实验室，为未来前沿应用进行技术储备。\n\n　　“有组织科研”，不止于“光镊”。“2025年以来，江苏‘双高协同’试点单位累计组织产学研对接、路演等活动594场次，合作开展技术攻关项目779项、总投入超过17.4亿元。”江苏省科技厅厅长徐光辉介绍。\n\n　　瞄准学科前沿布局产业赛道——\n\n　　“公司刚启动运营，就收到了一张70万元的订单！”无锡高新区一栋新厂房内，禾糖生物工程（无锡）有限公司总经理、江南大学生物工程学院副教授张洪涛喜出望外。\n\n　　这份喜悦，源于又一场“双高协同”。无锡高新区科技工业和信息化局副局长王澄介绍，江南大学向无锡高新区开放了由约500台尖端设备、1800名研究生导师组成的“创新家底”。“验证在高校—中试在平台—孵化在园区”，无锡高新区对创新项目开展“有组织转化”，推动张洪涛的“母乳寡糖绿色生物制造”项目落地孵化。\n\n　　截至目前，试点高新区已梳理企业端技术需求1383条，试点高校梳理并促成1040项可转化科技成果与企业对接，涉及电子信息、先进制造和生物医药等领域，入选国家高新区新赛道培育重点园区9个。\n\n　　深化改革破除卡点堵点——\n\n　　发展学术还是投身产业？如今不是非此即彼的单选题。\n\n　　海外留学归国博士何鹏近日同时入职苏州科技大学和苏州高新区一家人工智能企业，在校企之间“自由切换”，得益于江苏对人才引进模式的探索。江苏出台《“双高协同”政策指南清单》和《“双高协同”改革指引清单》，试点高校联合结对高新区，开展“校招共用”“校聘企用”等。\n\n　　创新资源如何跟上？\n\n　　不久前，中国药科大学生命科学与技术学院教授徐寒梅到南京鼓楼高新区注册公司，融资遇难，转化进程一度卡了壳。\n\n　　“人才团队到哪，创新资金跟投到哪”，依照《“双高协同”政策指南清单》，南京市鼓楼区、中国药科大学联合社会投资机构共同设立南京生物医药研发转化基金，一期总投资近6000万元，支持包括徐寒梅的肿瘤靶向药研发在内的3个成熟度高、具有示范效应的项目。\n\n　　截至“十四五”末，江苏高新技术产业产值占规上工业比重达52.1%，高新技术企业超6.1万家，研发人员超126万人。\n\n　　“牢记习近平总书记殷殷嘱托，奋进‘十五五’，江苏将发挥科教资源丰富和高新区实力强的叠加优势，开展‘双高协同’，努力探索出一条因地制宜发展新质生产力的新路子。”江苏省委书记信长星表示。', 0, 1, '2026-03-22 17:32:55', 1, 0, '2026-03-22 17:32:55', '2026-03-22 17:32:55');
INSERT INTO `news` VALUES (12, '干在实处 奋勇争先（创造经得起实践、人民、历史检验的实绩）  ——从福建福州机关效能建设看真抓实干', '福建福州市政务服务中心，“马上就办  真抓实干”8个大字矗立楼顶，在阳光下熠熠生辉。\n\n　　“要大力提倡‘马上就办’的工作精神”“‘马上就办’加上‘真抓实干’，我们就能切实转变作风，把工作落到实处，开创新局面”……上世纪90年代初，时任福州市委书记的习近平同志部署推动机关效能建设，直指作风积弊。习近平同志身体力行、率先垂范，为广大党员干部树立了光辉典范。\n\n　　三十余载光阴荏苒，实干精神历久弥新。“马上就办、真抓实干”在赓续相传中发扬光大，在守正创新中与时俱进，激励广大党员干部树牢正确政绩观，始终干在实处、奋勇争先。\n\n　　效能革命是一场永不停歇的自我革命\n\n　　上午9点，福州市民林婉清来到市政务服务中心办理二手房过户手续。将一沓材料递进综合窗口后，几分钟事就办完了，林婉清高兴地按下“服务满意”的按键。\n\n　　一栋楼办公，群众少跑路。所有审批事项汇聚于此，群众进一扇门，办所有事。\n\n　　这一切，始于上世纪90年代初一个重要的决定。当时，“办事难、办事慢、办事繁”问题备受社会诟病。习近平同志果断决策，倡导实行投资项目审批“一栋楼办公”，将多个部门办事窗口集中在一起，让企业群众“办事不用满城跑”。这开创了全国集中行政审批的先河。\n\n　　“那是一场刀刃向内的自我革命。”福州市行政服务中心管委会相关负责人说，“习书记当时说，‘我们要办的事很多，要为改革开放提供一个良好的软环境，这就需要提倡一种满负荷的精神，反对拖拉扯皮和人浮于事，提高办事效率，做到今日事今日毕。’这句话，我们始终牢记于心。”\n\n　　要想得人心、谋发展，好的作风是关键。从“一栋楼办公”到“一窗通办”，再到如今的“一网通办”，这场自我革命从未停歇，机关效能不断提升。如今，福州将“马上就办、真抓实干”写入行政服务条例。福州市政务服务中心已有超60家行政单位入驻，办理审批事项超2000项，很多高频事项正从“最多跑一趟”向“一趟不用跑”优化升级。\n\n　　“过去群众围着部门转，现在是数据围着群众转。”福州市行政服务中心管委会审批处工作人员张泽雅说。近年来，福州创新推出“高效办成一件事1+N”，支持企业与群众将主事项与多个关联事项灵活组合，实现“一次申请、一窗受理、并联审批、集成办结”。目前，福州已推出50组“一件事”服务场景，材料精简率达68.1%，审批时限压减63.9%。\n\n　　行走八闽大地，政务服务中心、便民服务大厅成为一道道温暖的风景线，“最多跑一趟”“一趟不用跑”正从承诺变成现实。\n\n　　说到做到是最好的营商环境\n\n　　一声悠长的汽笛响起，一艘满载印度尼西亚咖啡和棕榈油的货轮缓缓靠泊福清市元洪码头。\n\n　　“30多年前，这里还是一片滩涂。”站在元洪投资区规划展示馆的观景平台上，福州新区元洪功能区管委会副主任钟江伟说，“1991年，时任福州市委书记的习近平同志带领考察组访问印度尼西亚，动员侨领回乡投资。从此，福清湾畔，‘一片滩涂地’逐渐蜕变为国际化产业园区。”\n\n　　正是那次擘画，全国首个侨办开发区——元洪投资区在1992年诞生。\n\n　　然而，随着福州跟国内外城市的交流越来越多，基础设施渐渐跟不上了。那时，国家还没有在福州建机场的规划，福州决定自筹资金，迎难而上：干部群众筹一部分钱，华侨华人捐一部分，财政争取一部分，国家再补贴一部分。经过多年建设，长乐国际机场1997年正式通航。此后，为适应扩大对外开放的需要，福州全面推进深水码头、高速公路、城市快速路等一批重大基础设施建设。\n\n　　硬件设施跟上了，招商力度更大了，可仍有不少外商在观望。问题出在哪？\n\n　　“不说则已，说了就要过问到底”“既然想到这件事，提出这件事，就要办成这件事，办好这件事”……习近平同志当年对营商环境的洞察，给出了答案：不仅要“马上就办”，还要“真抓实干”，对企业的承诺要说到做到。\n\n　　“一栋楼办公”“一条龙服务”推广开来，“一窗受理、集成服务”等模式持续创新……冠捷集团、东南汽车等一批企业纷纷落户福州，福州保税区、福清融侨经济技术开发区等迅速崛起。\n\n　　如今，从闽江之畔到武夷山下，从特区窗口到老区苏区，“马上就办、真抓实干”的作风成为福建营商环境的一块金字招牌。\n\n　　在福建长德蛋白科技有限公司的中央控制室，巨大的屏幕上跳动着从印尼种植园到福州生产线全链条的数据流。一粒粒来自苏门答腊岛的棕榈仁，在这里经过精深加工后变为高端植物蛋白产品，销往全球。\n\n　　“从项目签约到投产，‘园区服务专班’全程驻点，任何问题都是‘马上就办、办就办好’。”公司执行董事张靖芳感慨，“这种说到做到的态度，这种真抓实干的氛围，正是我们选择这里的原因。”\n\n　　抓作风贵在讲认真\n\n　　晚上8点，福州市机关效能建设领导小组办公室依然灯火通明。墙上的巨幅重点项目进展“作战图”，密密麻麻标记着全市重点项目的最新进展。其中，一些项目被着重做了记号——这是当前督查任务的“重中之重”。\n\n　　“效能建设，核心在‘效’，关键要‘能’。”福州市效能办负责人一边查看“作战图”，一边用电脑打开“效能福建”平台，界面立刻切换到福州长乐国际机场二期扩建工程的项目详情。“这就是近期我们重点督办的重大项目之一。经过效能督查组现场协调推动、一线督帮，为项目在2026年6月建成投用赢得了宝贵时间。”\n\n　　“‘马上就办’的关键，就是要抓好督查工作，要‘回头看’。”担任福州市委书记时，习近平同志提出“马上就办”的同时，完善督查机制、建设常态机制，确保党员干部把工作干在实处，落地见效。此后，“首问责任制”“限时办结制”“一线督帮”等诸多着眼于“马上就办”的办事机制不断推出，坚持至今。\n\n　　习近平同志当年的要求，成为福州市效能办的重要工作遵循。从早期的明察暗访、专项督查，到如今的“互联网+督查”、大数据精准监测，手段在迭代，但“问题导向、动真碰硬、一抓到底”始终不变。\n\n　　“习书记说过，‘抓而不紧，等于不抓；抓而不实，等于白抓’。”福州市效能办负责人表示，抓作风建设贵在讲认真。当地建立“发现问题—精准交办—限时整改—跟踪督办—结果反馈—评估问效”的效能督查全流程闭环。其中，2025年以来，通过运用“一线督帮”机制，推动相关部门和单位担当作为，协调解决用地报批、资金拨付、要素保障等难题120余项。\n\n　　作风正则人心顺，作风好则事业兴。正确的政绩观，不在口号里，而在一件件办成的实事里。如今，福州市深入开展“深学争优、敢为争先、实干争效”、持续推进“奋勇争先”行动，“马上就办、真抓实干”不断内化为广大党员干部的自觉行动，为推动经济社会高质量发展蓄积起澎湃动力。', 0, 1, '2026-03-22 17:33:20', 1, 0, '2026-03-22 17:33:20', '2026-03-22 17:33:20');
INSERT INTO `news` VALUES (13, '加快“以竹代塑”发展 形成高效利用模式  小竹子撑起大产业（向新向优的中国产业）', '一架“竹翅膀”无人机，开辟低空经济绿色新赛道。\n\n　　今年年初，竹基倾转旋翼无人机在天津首飞成功，标志着我国在竹基复合材料航空应用领域取得重大突破。\n\n　　“机身竹材应用比例超过25%，蒙皮结构全部采用自主研发的高性能竹基复合材料，在全球固定翼无人机中尚属首例。”国际竹藤中心主任覃道春介绍，该无人机在性能和成本方面具有双重优势，整机重量相比于轻质高强的碳纤维材质下降超20%，竹青薄片材成本仅为普通碳纤维布的1/4左右。\n\n　　我国是世界上竹类资源最丰富的国家，拥有近800万公顷竹林，年均生产竹材1.5亿吨。\n\n　　2022年11月，国家主席习近平向国际竹藤组织成立二十五周年志庆暨第二届世界竹藤大会致贺信时指出，中国政府同国际竹藤组织携手落实全球发展倡议，共同发起“以竹代塑”倡议，推动各国减少塑料污染，应对气候变化，加快落实联合国2030年可持续发展议程。\n\n　　我国深入实施“加快‘以竹代塑’发展三年行动”，竹产业规模持续壮大，初步形成品类齐全、业态丰富、特色明显的竹产业体系，形成“吃干榨净”全竹高效利用模式。\n\n　　向新向优，小竹子撑起大产业。截至目前，我国竹产品种类突破1.5万种，竹产业年产值超5200亿元。\n\n　　——竹产品种类丰富，应用场景更加多元。\n\n　　走进江西赣州森泰竹木有限公司，一架竹管琴引人驻足，竹槌轻敲，发出的声音悦耳动听。\n\n　　“传统管琴的机械结构与创新设计的竹制音板、共鸣部件相结合，不仅保留了管琴的基本演奏特性，还融入了竹材的独特音色。”公司总经理许贺介绍，公司还可生产建筑用竹结构材、竹装饰材及室内户外竹家具、竹配件等1500余种优质产品。\n\n　　竹餐具、竹膜袋在日常生活中广泛使用，竹格栅、竹格淋水填料等在建筑施工、工业冷却系统等领域逐步推广，竹纤维复合材料成功应用于汽车内饰……作为绿色、低碳、可降解的生物质材料，竹子正成为塑料、钢材等传统材料的重要替代品，助推实现“双碳”目标。\n\n　　“以竹代塑”应用场景更加多元。国家林草局、国家发展改革委更新发布《“以竹代塑”主要产品名录（2025年版）》，拓展了竹制品替代塑料的应用范围。工业和信息化部、住房城乡建设部、国家邮政局等部门积极推动“以竹代塑”产品在建筑建材、快递包装等重点领域落地。福建、浙江、四川、安徽等地出台专门文件，鼓励在住宿餐饮、生活服务、文化旅游等领域使用竹制品替代塑料制品。\n\n　　——核心技术不断突破，打破传统应用边界。\n\n　　四川大竹县东柳河护城河污水干管二标工程现场，施工人员把竹缠绕复合管精准铺设在沟槽中，搭起东柳河护城河片区的污水收集与输送通道。\n\n　　“我们自主研发的竹缠绕复合材料技术，可将竹材加工成大口径压力管道、城市综合管廊甚至高铁列车车厢，具有质轻高强、保温隔音、耐候耐腐、综合成本低、施工便捷等诸多优点，能广泛替代钢材、水泥等传统高能耗材料。”浙江鑫宙竹基复合材料科技有限公司董事长叶柃介绍。\n\n　　作为我国首创的基建新材料，竹缠绕管道在市政、水利、交通等领域实现规模化应用，目前已在11个省份铺设700余公里，生产效率提升25%，单位成本下降13%。\n\n　　科技创新是竹产业向新发展的核心引擎。通过设立“十四五”国家重点研发计划“揭榜挂帅”项目、国家自然科学基金重大项目等，竹纤维分级利用与复合材料制造等一批技术难题迎刃而解，国家林草局累计发布37项“以竹代塑”重点科技成果。钠离子电池硬碳负极材料、潮流家具和时装……新型竹质材料不断打破传统应用边界。\n\n　　——全链条融合发展，提升产业附加值。\n\n　　云南大关县，吉食道（云南）食品科技有限公司靖安工厂内，现代化竹笋加工生产线高效运转，一辆辆货车满载竹笋制品驶往各地。“销售旺季，笋片、笋条、清水笋、泡椒笋等产品供不应求。”工厂综合管理部负责人张琼说。\n\n　　上游培育规模经营主体，打通采伐、收储等堵点；中游做强竹家居、竹纤维制品等主导产业，发展竹医药化工、竹生物质能源等新兴产业；下游推动竹产业与文旅、康养、文创等业态融合发展。\n\n　　各地因地制宜，打造全链条、多功能、高值化的产业体系，“一根竹子吃干榨净”的全竹高效利用模式纷纷落地。从竹笋加工、竹制品初级生产，向“竹科技+竹文旅+竹碳汇”多元延伸，去年，福建南平市竹产业总产值超500亿元。推出赏竹、品竹、玩竹全链条体验，去年上半年，四川兴文县僰王山竹文旅融合区接待游客180万人次。\n\n　　截至目前，全国竹加工企业达1万多家，全产业链吸纳就业人数超过2900万人。\n\n　　国内竹产业提质升级的同时，各地积极推动竹产品、竹技术、竹装备“走出去”，为全球“以竹代塑”和环境保护提供中国方案。福建尤溪县28万亩竹林获得国际FSC（森林管理委员会）认证，拿到“国际绿色通行证”后出口产品溢价达20%。尤溪永丰茂纸业用竹纤维研发的环保餐具，能够替代塑料制品，去年，相关产品出口额同比增长35%。\n\n　　国家林草局相关负责人表示，“十五五”时期，我国将进一步健全政策保障体系，加大竹产业循环经济发展支持力度，加强“以竹代塑”产品技术全链条标准体系建设。同时，强化科技创新和产业创新深度融合，打造竞争力强的竹产业集群，引领“以竹代塑”全面转型升级。', 0, 1, '2026-03-22 17:33:40', 1, 0, '2026-03-22 17:33:40', '2026-03-22 17:33:40');
INSERT INTO `news` VALUES (14, '民生融合，深化琴澳一体化发展（观沧海）', '“十五五”规划纲要提出，“深化琴澳一体化发展”，为横琴粤澳深度合作区（以下简称“合作区”）建设擘画新蓝图。今年全国两会上，围绕深化琴澳一体化发展，澳区全国人大代表、全国政协委员热议合作区民生融合，“民生为桥、民心相通”已成为合作区建设的共识。\n\n　　2025年是合作区第二阶段建设开局之年。合作区紧扣“澳门+横琴”定位，以制度创新破除壁垒，在产业协同提速的同时，把民生融合摆在突出位置。民生连着民心，民心凝聚合力，唯有民生相融，方能实现民心相通。\n\n　　跨境便利“无感化”，通关升级赋能同城生活。通关之便，是民生融合的重要一步。合作区以基础设施“硬联通”推动民生服务“优联通”，琴澳有形边界愈发“无感”。横琴在全国首创合作快捷通道“刷脸”免证通关模式，跨境学生专车试行免下车通关……系列务实举措打造琴澳“半小时生活圈”。2025年，横琴口岸客流量首次突破3000万人次，繁忙的人潮车流见证琴澳交融的勃勃生机，琴澳渐从“双城”变“同城”。\n\n　　政务服务“无界化”，打破地域壁垒联通民心。政务连着民心，服务加深融合。过去，琴澳居民为跨境办事往返奔波，办理流程繁琐。如今，琴澳联合解决“痛点”，积极深化政务服务，推广澳门政务24小时自助服务中心，设立琴澳遥距服务柜台，实现从“线下跑”变“线上办”，实现“琴事澳办”“澳事琴办”双向直通。打破政务壁垒，让琴澳居民办事更省心、生活更安心。\n\n　　医疗资源“一体化”，健康保障筑牢民生底线。健康是民生之基，医疗融合是琴澳居民的关切事。合作区推进琴澳医疗一体化，当前，琴澳两地医院共建联合专科门诊，实现“点对点”跨境转运，189名澳门医生完成执业注册，545个品规的澳门药品跨境使用，澳门医疗券扩展至合作区……越来越多澳资医疗资源和福利走进合作区，打通跨境就医“最后一公里”，以更便捷、高效的服务守护健康。\n\n　　养老服务“标准化”，银发岁月乐享幸福安康。养老安，则家庭安。让澳门长者老有所养、老有所安，是琴澳民生融合的重要课题。合作区以琴澳融合居家社区养老服务标准化试点为抓手，完善跨境养老保障链条，建成4个居家养老服务中心、7个长者饭堂，引入澳门社团提供服务，落地“粤澳养老通”实现养老金跨境划转，解决澳门长者的“后顾之忧”。温情服务衔接养老需求，让银发生活更有质感，彰显琴澳融合的民生厚度与人文温度。\n\n　　民生无小事，枝叶总关情。合作区建设不仅是发展空间的拓展延伸，还承载着琴澳居民的殷切期盼，更关乎民生福祉的提升、民心所向的凝聚。今年是“十五五”规划开局之年，也是合作区第二阶段建设的关键之年。站在新起点上，期待合作区书写更有温度、更富成效的民生答卷，打造澳门居民安居乐业的幸福家园，为粤港澳大湾区融合发展贡献鲜活的“横琴经验”。', 0, 1, '2026-03-22 17:34:06', 1, 1, '2026-03-22 17:34:06', '2026-03-22 17:34:06');
INSERT INTO `news` VALUES (15, '璀璨灯火映照湾区同心（微言）', '夜幕降临，广东广州南沙湾畔华灯齐放。“星河驰骋•骏马腾云”灯组气势如虹：11匹骏马昂首挺立，象征湾区“9+2”城市同心共进。\n\n　　前不久，以“湾区同心  华彩千秋”为主题的粤港澳大湾区灯会在广州南沙区开园，五大展区、上百组灯景，将持续点亮至5月10日。继去年首届超71万人次参观量，本届灯会再掀热潮，连日来游人如织。\n\n　　灯会魅力，源于人文湾区的独特韵味。从动态特效展现“南沙花神”苏醒，到粤港澳非遗元素跃然眼前，从复古怀旧街景勾勒湾区旧日霓虹，到十五运会吉祥物“喜洋洋”“乐融融”炫彩亮相，腾跃光影映照着人文湾区日新月异。此外，灯会通过虚拟现实互动、人工智能、全息投影等科技，让传统灯火更加灵动、更为震撼。人文湾区韵味不断拓展延伸：夜幕下，游客在移步换景间赏灯游园，体验传统文化、领略微缩湾区风光；白昼间，既可漫步红树林湿地，也可游览名胜古迹，尽享绿美生态与人文底蕴。传统与现代交融、人文与科技并进、生态与发展共生，共同展现人文湾区生动画卷。\n\n　　灯火深处，更见湾区融合的温情图景。“同根同源，湾区和韵”展区，熟悉的粤语金曲悠扬回荡、经典的影视画面流光重现，让往来其间的港澳同胞倍感亲切；粤港澳青少年共同设计“少年创想灯廊”，孩子们的笔触不仅点亮夜空，更绘就了同心同向的未来。从情感共鸣到携手共创，血脉相连的深厚联结，成为持续推动大湾区民心相通、融合发展的深层力量。\n\n　　站在“十五五”规划开局之年，粤港澳大湾区以一场璀璨的视觉盛宴，串联起共同记忆与美好愿景。一盏盏灯，映照着中华文化的历久弥新；一处处景，彰显着粤港澳三地的同心合力。人文湾区的独特魅力，在时代星河中璀璨夺目；湾区融合的生动画卷，在新征程上气象万千。', 0, 1, '2026-03-22 17:34:21', 1, 0, '2026-03-22 17:34:21', '2026-03-22 17:34:21');
INSERT INTO `news` VALUES (16, '香港九龙深水埗东社区客厅帮助街坊解决生活痛点——  劏房住户的“第二个家”（香江在线）', '开阔明净的空间、温馨雅致的装饰，大人们悠闲交谈，小朋友们开心玩耍……在香港九龙深水埗，深水埗东社区客厅在一片局促陈旧的临街门脸中格外显眼，这里已成为周边500多个劏房住户的“第二个家”。\n\n　　“早晨（早安）！”上午11点，社区客厅一开门，便热闹起来。忙完了准备工作，深水埗东社区客厅中心主任文怡乐熟稔地与陆续到来的街坊寒暄。一个小男孩乖巧地走近她，文怡乐温柔地摸摸他的头，夸奖了他的进步，孩子脸上绽开了花。对文怡乐而言，这是她每天的轻松时光，“每天有150至180人次的街坊过来，有的几乎每天都来，大家熟悉得就像家人一样。”\n\n　　深水埗东社区客厅启用于2025年6月，由香港特区政府牵头推动，招商局集团赞助场地，博爱医院向关爱基金申请营运经费并负责营运，以劏房住户为主要服务对象。\n\n　　“这里很宽敞、很温馨，是一个能让人感到舒服和放松的地方。”住户韩太太告诉记者，她和先生带着7岁的儿子在附近劏房租住了3年，狭窄的生活空间让做饭、洗澡都成为难题。自从登记为会员，社区客厅就成了自己家生活的主要场所。\n\n　　环顾社区客厅，备餐区、用餐区、学习室、儿童游戏角、自助洗衣间、淋浴间等一应俱全，实用面积300多平方米。\n\n　　“孩子放学后，就送他去学习室写作业。趁这个时间，我买菜做饭，等他爸爸下班一起用餐。在这里洗澡、洗衣服，还能陪孩子在游戏区玩。”韩太太心满意足。\n\n　　最令她惊喜的，还是孩子的变化。“以前闹着不写作业，来到这里，有小朋友一起学习，还有义工辅导功课，功课明显进步了。”韩太太说，孩子在社区客厅有很多玩伴，懂得了与人分享，自理能力明显提升。\n\n　　“我们每天下午都有辅导班，目前约有25位学生参加，会有义工辅导功课，这项服务很受欢迎。”作为博爱医院儿童及家庭服务高级服务经理、从业近20年的专业社工，文怡乐对住房困难家庭养育子女的痛点深有体会。\n\n　　她介绍，深水埗的劏房住户比较集中，目前在社区客厅登记的劏房住户中约四成是有孩子的家庭，普遍面临孩子放学后没人带、功课辅导难、家庭关系紧张等问题。社区客厅不仅为劏房住户拓展生活空间，也提供儿童暂托、生活资讯等服务，编织起一张社区支援网络。\n\n　　对于独自带两个儿子生活的马女士来说，社区客厅是让她感到社会温暖、重燃生活希望的地方。\n\n　　“我们住在不到14平方米的房间里，两个孩子一个9岁、一个7岁，天天打闹。”马女士去年做了一场大手术，无法工作，暂靠领取政府资助生活，逼仄的居住条件、养育两个孩子的重担，压得她喘不过气来。\n\n　　2025年8月，马女士偶然得知深水埗东社区客厅。“两个孩子第一次进来，就不肯走了。现在，孩子放学后就来，我也开心多了，不再把自己关在劏房里。在这里，有物资支援、集体活动，我还经常收到一些贴心的小礼物。”马女士说。\n\n　　学习室的书架上，摆放着公共图书馆赠阅的书籍；用餐区的冰箱里，有公益机构捐赠的盒饭；大厅墙上，贴满多个机构举办活动的资讯……“社区客厅营运至今，很多大专院校、地区团体、企业包括政府部门，都希望在这里合作办活动。”在文怡乐看来，社区客厅也是社会各界爱心汇聚的枢纽，让各类资源精准匹配到真正有需要的居民手中。\n\n　　在接受记者采访时，马女士的两个儿子静静坐在她身边，偶尔插话帮妈妈补充回答。她不时转头看向他们，满眼欣慰。\n\n　　“现在两兄弟很乖，很少打架了，学习也用功，哥哥的成绩拔尖。”马女士说，有了社区客厅的帮忙，自己可以安心出去找工作，给两个孩子创造更好的生活，希望他们将来有了能力，也能帮助那些有需要的人。', 0, 1, '2026-03-22 17:34:34', 1, 0, '2026-03-22 17:34:34', '2026-03-22 17:34:34');
INSERT INTO `news` VALUES (17, '让科学教育贴合学生成长曲线（师说）', '中学阶段是激发科学兴趣、培育科创素养的黄金时期，在教育科技人才一体化推进中，不少学校积极探索科学教育新路径。北京一零一中的课堂上，从“芯片与计算思维”到“空天科学的实践之旅”，不同课程吸引着不同学段的学生，有的人为调试全加器反复尝试数百次，有的人为模拟月球基地生态舱测算参数、打磨方案……通过学科融合、学段贯通、校所协同，引导学生接触鲜活实践，浸润式提升科学素养，是我们近年来破题的主要思路。\n\n　　传统科学教育往往重理论、轻实践。如何推动学科融合与实操落地，让知识用来解决真问题？手脑并重的教学模式，可以将知识融入真实科研项目。比如，组织师生一起分析航天发射基地如何选址、航天服如何设计，有机融合地理、物理、化学、材料、工程设计等多学科知识……每一门科创课程都配套对应的动手实践环节，每一个项目都让学生亲历“问题界定—设计实践—测试迭代”的完整过程。做中学、研中学，才能引导学生实现知识与能力的双向转化。\n\n　　科学教育不可能一蹴而就，重在阶梯式培育。依靠学段贯通，学校形成科学连贯的育人链条。考虑到不同年龄段学生的认知差异，课程体系设计要遵循梯度化规律：初中芯片课程，主要从机械式加法器入手，侧重兴趣激发和动手能力培养；高中空天课程，则以火星探测器的发射方案设计、月球基地设计为载体，聚焦深度研究和创新实践；人工智能、STEM（科学、技术、工程、数学）综合课程也都划分启蒙、基础、提高、挑战等不同层级……课程设计要避免“一刀切”，根据不同学段特点拆解教学目标，让科学教育贴合学生成长曲线，慢慢扎根、缓缓结果。\n\n　　科学教育的痛点之一，在于校内资源的单一与前沿科研的脱节，校所协同是建立连接的有效方法。为摒弃校内单打独斗的传统模式，学校与中国科学院计算所、空天信息创新研究院等科研院所建立长期稳定合作。科研人员与校内教师组成联合教学团队，共同研发课程、编写教材，如芯片研发、小卫星设计、遥感技术应用等，为课堂注入新鲜活力；同时，组织学生走进实验室、企业车间，近距离接触科技一线。\n\n　　（作者为北京一零一中校长）', 2, 1, '2026-03-22 17:34:51', 1, 0, '2026-03-22 17:34:51', '2026-03-22 17:34:51');
INSERT INTO `news` VALUES (18, '教育资源如何适配学龄人口变化（教育时评）', '2026年、2029年、2032年——我国学龄人口将经历“排浪式”变化，初中、高中、高等教育学龄人口在这3个年份依次“达峰”，这一趋势给教育资源配置带来挑战。\n\n　　人口变化与资源配置“掰手腕”，考验着教育治理的智慧。一是时空错配，一边是部分幼儿园、小学生源减少，一边是高中阶段学位持续承压；二是区域分化，城镇学校班额超标与乡村学校“空心化”形成鲜明对比；三是师资波动，部分地区编制僵化难以应对师资阶段性紧缺或过剩，不同学段、不同学科师资超编与缺编并存。再往前推一步，又会影响到教师教育。\n\n　　今年全国两会，“适应学龄人口结构变化，推进教育资源布局结构调整”首次写入《政府工作报告》。教育部部长怀进鹏在民生主题记者会上明确表态，加强前瞻研判，重点加大人口净流入城镇和基础薄弱地区学位供给，因地制宜加强教育资源跨学段调整。这些释放出一个清晰信号：教育资源不仅要“跟着人跑”，更要“跑在变化前”。\n\n　　一些地方已经敏锐捕捉到人口变化趋势，开始“逐浪而行”：广东广州、陕西西安等地开展需求预测，提前发布学位预警，缓和热点地区和热门学校的学位供需矛盾；山东青岛探索“幼儿园与小学低年级”“小学高年级与初中低年级”教师共享使用模式，加强教师贯通培养，应对不同学段生源的阶段性变化；江苏实施义务教育强校提质行动，鼓励有条件的地区适当缩小义务教育班额，探索小班化教学。\n\n　　从“被动应对”到“主动预警”，从“静态布局”到“动态流动”，探索的背后都是“投资于人”——在学龄人口结构变化的“量变”中，撬动教育高质量发展的“质变”，切实回应人民群众“上好学”的殷切期盼。\n\n　　具体来看，布局调整的重心，不只在增减校舍、学位等硬件设施，更在盘活师资、课程等软件资源。关键是要打破城乡、校际、学段之间的壁垒，让优质教育资源真正流动起来，在动态配置中顺应人口变化趋势。\n\n　　部分区域、学段生源出现回落，也为育人方式变革打开了“窗口期”。班级规模降下来，课堂形态活起来，个性化培养才有更多空间落地，让每一个孩子都能被看见、被关心、被赋能。从现实条件看，北京、上海、江苏等地将小班化作为构建优质均衡基本公共教育服务体系的重要抓手，进行了系统性规划，积累了宝贵经验。\n\n　　要注意的是，人口在变，但教育公平的底线不能变。教育不能只算“规模账”，办好必要的乡村小规模学校至关重要。这些扎根乡土的校园，承载着乡村孩子的成长希望，绝不能因生源减少就简单撤并。应强化保障，通过城乡学校结对、集团化办学、骨干教师轮岗等机制，将优质资源下沉基层，让乡村学校从“小而弱”走向“小而美”“小而优”。\n\n　　3月13日，“十五五”规划纲要正式发布。“健全与人口变化相适应的教育资源配置机制”“有序推进小班化教学”“新增高等教育资源适度向人口大省和中西部地区倾斜”……一系列重要部署，为破解教育资源供需矛盾、推动教育优质均衡发展指明发展路径。面对学龄人口“排浪式”变化，不能简单做“加减法”，而要转向更科学的调结构、优布局、提质量。把人口变化的压力，转化为教育提质增效、促进公平的重要机遇。', 2, 1, '2026-03-22 17:35:14', 1, 0, '2026-03-22 17:35:14', '2026-03-22 17:35:14');
INSERT INTO `news` VALUES (19, '农学生“玩泥巴”，有啥学问？（在一线）', '俯身观察不同土层的颜色、纹理，仔细辨别砂粒与黏土的触感差异，轻轻搓捻湿润的土条……北京百望山森林公园，一群中国农业大学学生围着一处局部土壤剖面，专注地进行一场野外认地实验。\n\n　　“从山前冲积平原，到山前坡地，再到山地，这里拥有多种土地类型。不同类型的基岩、母质特点各异，发育形成的土壤特性也各不相同。”土地科学与技术学院副教授卢奕丽指着眼前的剖面说，“大家依次下来取土，亲身感受一下，地形、气候、水文等因素，是如何共同塑造我们脚下这片土地的。”\n\n　　这是中国农大专业必修课“土壤学实验”的教学现场——感官法测定土壤质地。这门面向农学、资源与环境科学等多个专业开设的课程，因独特的教学方式，被学生称为“玩泥巴课”。\n\n　　为什么要开设这门课？“农业科学离不开土地，但现在不少学生对农业生产接触较少，对土壤的认知更多停留在书本概念上。”卢奕丽道出初衷，“我们想做的，就是为学生搭建从抽象理论走向生动实践的桥梁。”\n\n　　课程的重要方法是“感官先行”，亲手揉捏土片、搓捻土条、塑形土球，在指尖与泥土的直接对话中，建立对不同质地土壤的经验性判断。“当手指能够分辨颗粒的粗细，眼睛能够识别土色的深浅，一套属于个人的‘土壤感官词典’就初步建立了。”卢奕丽解释，“有了这个基准，今后面对未知的土壤，才能做出更准确的判断。”\n\n　　当然，感官认知并非终点，还需用量化方法验证。形成初步判断后，教师会引导学生使用土壤比色卡、稀盐酸反应测试、紧实度仪等工具获取客观数据，让主观感受与科学指标相互印证。\n\n　　“以前觉得土壤学很抽象，现在才发现泥土里全是学问。”农学院学生吴佳仪很有感触，“当手指的感觉与仪器测得的数据对上号，那种‘秒懂’的喜悦特别真实。”\n\n　　围绕学生需求，课程团队持续推进教学改革。“我们将传统的土壤酶活性测定方法，升级为操作更有效率的试剂盒法。这样，学生就能从繁琐的操作中解放出来。”土地科学与技术学院副教授朱堃说，“培养科研思维，比单纯训练操作技能更重要。”\n\n　　与此同时，实地教学与虚拟仿真的结合也在探索中。“目前，野外教学只有4学时，时间紧张、地点也局限。”资源与环境学院实验教学中心党支部书记王雅婧介绍，“我们计划引入人工智能技术，补充北京以外典型土壤类型的虚拟教学资源，让学生即使足不出校，也能接触更多样的土地，弥补实地教学的局限。”\n\n　　“从完全陌生到能分辨不同土壤，自己的进步看得见”“掌握新技能，对今后从事农业生产实际很有帮助”……课后评价的留言板中，许多学生表示收获满满。\n\n　　而更深刻的转变，发生在认知层面。更多学生开始真正理解土壤在农业生产中的地位，更加坚定了扎根农业的信念。“土壤不仅是作物生长的介质，也是生态系统的重要组成，合理保护和利用土壤，是农业生产和国家粮食安全的基础。”吴佳仪表示，要努力学习，成为既懂理论又善实践、既会科研又接地气的人，做知农爱农、强农报国的践行者。\n\n人 民 网 版 权 所 有 ，未 经 书 面 授 权 禁 止 使 用', 2, 1, '2026-03-22 17:35:27', 1, 1, '2026-03-22 17:35:27', '2026-03-22 17:35:27');

-- ----------------------------
-- Table structure for payment
-- ----------------------------
DROP TABLE IF EXISTS `payment`;
CREATE TABLE `payment`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '支付ID',
  `booking_id` bigint NULL DEFAULT NULL COMMENT '预约ID',
  `service_id` bigint NULL DEFAULT NULL COMMENT '服务ID',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `payment_method` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '支付方式(BALANCE,WECHAT,ALIPAY)',
  `amount` decimal(10, 2) NOT NULL COMMENT '支付金额',
  `transaction_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '交易流水号',
  `status` int NULL DEFAULT 0 COMMENT '状态(0:待支付,1:已支付,2:已取消,3:已退款)',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '备注',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_booking_id`(`booking_id` ASC) USING BTREE,
  INDEX `idx_service_id`(`service_id` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_transaction_id`(`transaction_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 6 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '支付记录表' ROW_FORMAT = Dynamic;

